/// For a boolean type or a vector of boolean type, return false or a vector
/// with every element false.
static Constant *getFalse(Type *Ty) { return ConstantInt::getFalse(Ty); }

/// For a boolean type or a vector of boolean type, return true or a vector
/// with every element true.
static Constant *getTrue(Type *Ty) { return ConstantInt::getTrue(Ty); }

/// isSameCompare - Is V equivalent to the comparison "LHS Pred RHS"?
static bool isSameCompare(Value *V, CmpInst::Predicate Pred, Value *LHS,
                          Value *RHS) {
  CmpInst *Cmp = dyn_cast<CmpInst>(V);
  if (!Cmp)
    return false;
  CmpInst::Predicate CPred = Cmp->getPredicate();
  Value *CLHS = Cmp->getOperand(0), *CRHS = Cmp->getOperand(1);
  if (CPred == Pred && CLHS == LHS && CRHS == RHS)
    return true;
  return CPred == CmpInst::getSwappedPredicate(Pred) && CLHS == RHS &&
         CRHS == LHS;
}

/// Simplify comparison with true or false branch of select:
///  %sel = select i1 %cond, i32 %tv, i32 %fv
///  %cmp = icmp sle i32 %sel, %rhs
/// This may be simplified to:
///  %cmp = (%cond && icmp sle %tv, %rhs) || (!%cond && icmp sle %fv, %rhs)
/// but we only do the simplification when the select has one use.
/// The one-use restriction is important because this transform duplicates the
/// compare and the rest of the expression.
static Value *simplifyCmpWithSel(CmpInst::Predicate Pred, Value *Sel, Value *RHS,
                                 const SimplifyQuery &Q, unsigned MaxRecurse) {
  SelectInst *SI = dyn_cast<SelectInst>(Sel);
  if (!SI || !SI->hasOneUse())
    return nullptr;

  // Don't get into a cycle of creating and destroying selects.
  if (MaxRecurse == 0)
    return nullptr;

  Value *Cond = SI->getCondition();
  Value *TVal = SI->getTrueValue();
  Value *FVal = SI->getFalseValue();

  // Now that we have the components of the select, we can create the new
  // expression.
  Value *TCmp = simplifyCmpInst(Pred, TVal, RHS, Q, MaxRecurse - 1);
  if (!TCmp)
    return nullptr;

  Value *FCmp = simplifyCmpInst(Pred, FVal, RHS, Q, MaxRecurse - 1);
  if (!FCmp)
    return nullptr;

  // We are creating an expression of the form:
  //   (Cond && TCmp) || (!Cond && FCmp)
  // We can simplify this if TCmp and FCmp are constants.
  if (TCmp == FCmp)
    return TCmp;

  if (match(TCmp, m_True())) {
    // Cond || (!Cond && FCmp) --> Cond || FCmp
    return simplifyOrInst(Cond, FCmp, Q, MaxRecurse - 1);
  }
  if (match(FCmp, m_True())) {
    // (Cond && TCmp) || !Cond --> !Cond || TCmp
    Value *NotCond =
        simplifyUnOp(Instruction::Xor, Cond, getTrue(Cond->getType()), Q,
                     MaxRecurse - 1);
    return simplifyOrInst(NotCond, TCmp, Q, MaxRecurse - 1);
  }
  if (match(TCmp, m_False())) {
    // (Cond && false) || (!Cond && FCmp) --> !Cond && FCmp
    Value *NotCond =
        simplifyUnOp(Instruction::Xor, Cond, getTrue(Cond->getType()), Q,
                     MaxRecurse - 1);
    return simplifyAndInst(NotCond, FCmp, Q, MaxRecurse - 1);
  }
  if (match(FCmp, m_False())) {
    // (Cond && TCmp) || (!Cond && false) --> Cond && TCmp
    return simplifyAndInst(Cond, TCmp, Q, MaxRecurse - 1);
  }

  // If we can't simplify it, it's not worth creating the extra instructions.
  return nullptr;
}

/// Simplify a SELECT instruction.
static Value *simplifySelectInst(Value *Cond, Value *TVal, Value *FVal,
                                 const SimplifyQuery &Q, unsigned MaxRecurse) {
  // select true, X, Y  -> X
  // select false, X, Y -> Y
  if (auto *CondC = dyn_cast<Constant>(Cond)) {
    if (CondC->isAllOnesValue())
      return TVal;
    if (CondC->isNullValue())
      return FVal;
    if (auto *VecCond = dyn_cast<ConstantVector>(CondC)) {
      // select <C1, C2, ...>, X, Y
      // We can't simplify the whole thing to X or Y, but maybe we can simplify
      // some of the elements.
      if (TVal->getType() == FVal->getType() && isa<Constant>(TVal) &&
          isa<Constant>(FVal)) {
        // select <C, C, ...>, C, C -> C
        if (TVal == FVal)
          return TVal;

        // select <C1, C2, ...>, <cT1, cT2, ...>, <cF1, cF2, ...>
        //   -> <(C1?cT1:cF1), (C2?cT2:cF2), ...>
        if (isa<ConstantVector>(TVal)) {
          unsigned NumElts =
              cast<FixedVectorType>(VecCond->getType())->getNumElements();
          SmallVector<Constant *, 16> ResElts;
          for (unsigned i = 0; i != NumElts; ++i) {
            Constant *CondElt = VecCond->getAggregateElement(i);
            assert(CondElt && "All elements of vector constant must be non-null");
            if (CondElt->isAllOnesValue())
              ResElts.push_back(cast<Constant>(TVal)->getAggregateElement(i));
            else
              ResElts.push_back(cast<Constant>(FVal)->getAggregateElement(i));
          }
          return ConstantVector::get(ResElts);
        }
      }
    }
  }

  // select C, X, X -> X
  if (TVal == FVal)
    return TVal;

  Type *Ty = TVal->getType();

  // select C, C, Y -> select C, C, C where C is a constant
  if (isa<Constant>(TVal) && TVal == Cond)
    return TVal;

  // select C, X, C -> select C, X, X
  if (isa<Constant>(FVal) && FVal == Cond)
    return simplifySelectInst(Cond, TVal, TVal, Q, MaxRecurse);

  // select c, (op x, y), (op x, z) --> (op x, (select c, y, z))
  if (TVal->hasOneUse() && FVal->hasOneUse()) {
    if (auto *TVal_BO = dyn_cast<BinaryOperator>(TVal)) {
      if (auto *FVal_BO = dyn_cast<BinaryOperator>(FVal)) {
        if (TVal_BO->getOpcode() == FVal_BO->getOpcode()) {
          Value *LHS, *RHS;
          if (TVal_BO->getOperand(0) == FVal_BO->getOperand(0)) {
            LHS = TVal_BO->getOperand(0);
            RHS = simplifySelectInst(Cond, TVal_BO->getOperand(1),
                                     FVal_BO->getOperand(1), Q, MaxRecurse);
            if (RHS)
              return simplifyBinOp(TVal_BO->getOpcode(), LHS, RHS, Q,
                                   MaxRecurse);
          } else if (TVal_BO->getOperand(1) == FVal_BO->getOperand(1)) {
            LHS = simplifySelectInst(Cond, TVal_BO->getOperand(0),
                                     FVal_BO->getOperand(0), Q, MaxRecurse);
            RHS = TVal_BO->getOperand(1);
            if (LHS)
              return simplifyBinOp(TVal_BO->getOpcode(), LHS, RHS, Q,
                                   MaxRecurse);
          } else if (TVal_BO->isCommutative()) {
            if (TVal_BO->getOperand(0) == FVal_BO->getOperand(1)) {
              LHS = TVal_BO->getOperand(0);
              RHS = simplifySelectInst(Cond, TVal_BO->getOperand(1),
                                       FVal_BO->getOperand(0), Q, MaxRecurse);
              if (RHS)
                return simplifyBinOp(TVal_BO->getOpcode(), LHS, RHS, Q,
                                     MaxRecurse);
            } else if (TVal_BO->getOperand(1) == FVal_BO->getOperand(0)) {
              LHS = TVal_BO->getOperand(1);
              RHS = simplifySelectInst(Cond, TVal_BO->getOperand(0),
                                       FVal_BO->getOperand(1), Q, MaxRecurse);
              if (RHS)
                return simplifyBinOp(TVal_BO->getOpcode(), LHS, RHS, Q,
                                     MaxRecurse);
            }
          }
        }
      }
    }
  }

  // select c, (cast x to T), (cast y to T) --> cast (select c, x, y) to T
  if (auto *TC = dyn_cast<CastInst>(TVal)) {
    if (auto *FC = dyn_cast<CastInst>(FVal)) {
      if (TC->hasOneUse() && FC->hasOneUse() &&
          TC->getOpcode() == FC->getOpcode() &&
          TC->getOperand(0)->getType() == FC->getOperand(0)->getType()) {
        Value *V = simplifySelectInst(Cond, TC->getOperand(0), FC->getOperand(0),
                                      Q, MaxRecurse);
        if (V)
          return simplifyCastInst(TC->getOpcode(), V, Ty, Q, MaxRecurse);
      }
    }
  }

  // select c, (gep x, ...), (gep y, ...) --> gep (select c, x, y), ...
  if (auto *TGEP = dyn_cast<GetElementPtrInst>(TVal)) {
    if (auto *FGEP = dyn_cast<GetElementPtrInst>(FVal)) {
      if (TGEP->hasOneUse() && FGEP->hasOneUse() &&
          TGEP->getSourceElementType() == FGEP->getSourceElementType() &&
          TGEP->getNumOperands() == FGEP->getNumOperands()) {
        bool OperandsSame = true;
        for (unsigned i = 1, e = TGEP->getNumOperands(); i != e; ++i) {
          if (TGEP->getOperand(i) != FGEP->getOperand(i)) {
            OperandsSame = false;
            break;
          }
        }
        if (OperandsSame) {
          // The GEPs only differ in the base pointer.
          Value *V = simplifySelectInst(Cond, TGEP->getOperand(0),
                                        FGEP->getOperand(0), Q, MaxRecurse);
          if (V) {
            SmallVector<Value *, 8> Idxs(TGEP->op
